#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int x[N], y[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &x[i], &y[i]);
        }
        double totalArea = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                for (int k = j + 1; k < N; k++) {
                    double area = fabs((x[i] * (y[j] - y[k]) + x[j] * (y[k] - y[i]) + x[k] * (y[i] - y[j])) / 2.0);
                    totalArea += area;
                }
            }
        }
        printf("%.2f\n", totalArea);
    }
    return 0;
}

