const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readLine = () => input[idx++];
const readInt = () => parseInt(readLine());
const readIntArray = () => readLine().split(' ').map(Number);

let T = readInt();
while (T-- > 0) {
    let N = readInt();
    let points = [];
    for (let i = 0; i < N; i++) {
        points.push(readIntArray());
    }
    let totalArea = 0;
    for (let i = 0; i < N; i++) {
        for (let j = i + 1; j < N; j++) {
            for (let k = j + 1; k < N; k++) {
                let x1 = points[i][0];
                let y1 = points[i][1];
                let x2 = points[j][0];
                let y2 = points[j][1];
                let x3 = points[k][0];
                let y3 = points[k][1];
                let area = Math.abs((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2.0);
                totalArea += area;
            }
        }
    }
    console.log(totalArea.toFixed(2));
}
